if __name__ == "__main__":
    print("=" * 50)
    print("  Student Performance Evaluator (CLI)")
    print("=" * 50)
    try:
        attendance  = float(input("\nAttendance  (0-100) : "))
        assignment  = float(input("Assignment  (0-100) : "))
        quiz        = float(input("Quiz Score  (0-100) : "))
        mid         = float(input("Mid-term    (0-100) : "))
        study_hours = float(input("Study Hours/week    : "))
    except ValueError:
        print("Invalid input."); exit(1)

    r = evaluate_student(attendance, assignment, quiz, mid, study_hours)
    print("\n" + "-"*50)
    print(f"  Prediction  : {r['label']}")
    print(f"  Confidence  : {r['confidence']*100:.1f}%")
    print(f"  Performance : {r['performance']}")
    print("-"*50)
    print(f"\n{r['interpretation']}\n")
